    $adminBadge=New-Object System.Windows.Forms.Label;$adminBadge.Font=New-Object System.Drawing.Font("Segoe UI",7.5,[System.Drawing.FontStyle]::Bold);$adminBadge.AutoSize=$true;$adminBadge.Location=New-Object System.Drawing.Point(260,13);if($isAdmin){$adminBadge.Text="ADMIN";$adminBadge.ForeColor=$successColor}else{$adminBadge.Text="UTENTE";$adminBadge.ForeColor=$warningColor};$headerPanel.Controls.Add($adminBadge)
    $psVer="PS$($PSVersionTable.PSVersion.Major).$($PSVersionTable.PSVersion.Minor)";$verLabel=New-Object System.Windows.Forms.Label;$verLabel.Text="v3.0 | $psVer";$verLabel.Font=New-Object System.Drawing.Font("Segoe UI",7);$verLabel.ForeColor=$fgDim;$verLabel.AutoSize=$true;$verLabel.Location=New-Object System.Drawing.Point(1000,13);$headerPanel.Controls.Add($verLabel)
